'use client';

import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { useEffect, useState } from 'react';

const navItems = [
  { href: '/', label: 'Accueil' },
  { href: '/explore', label: 'Explorer la carte' },
  { href: '/explore#cooperatives', label: 'Les Cooperatives' },
  { href: '/#mission', label: 'Notre Mission' },
];

export default function SiteHeader() {
  const pathname = usePathname();
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 24);
    onScroll();
    window.addEventListener('scroll', onScroll);

    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  const isHomeTop = pathname === '/' && !scrolled;

  return (
    <header
      className={`fixed inset-x-0 top-0 z-50 mx-auto mt-3 w-[calc(100%-1.5rem)] max-w-[1420px] rounded-2xl px-5 py-3 transition-all duration-300 sm:w-[calc(100%-3rem)] lg:w-[calc(100%-5rem)] ${
        isHomeTop
          ? 'border border-transparent bg-transparent text-white'
          : 'border border-white/50 bg-white/75 text-palmier shadow-soft backdrop-blur-md'
      }`}
    >
      <div className="flex items-center justify-between">
        <Link href="/" className="font-semibold tracking-tight">
          Oasis Moderne
        </Link>

        <nav className="hidden items-center gap-4 text-sm md:flex">
          {navItems.map((item) => (
            <Link
              key={item.href}
              href={item.href}
              className={`rounded-full px-3 py-1.5 transition ${
                isHomeTop ? 'hover:bg-white/15' : 'hover:bg-palmier/10'
              }`}
            >
              {item.label}
            </Link>
          ))}
        </nav>

        <Link
          href="/explore"
          className="rounded-full bg-terracotta px-4 py-2 text-sm font-medium text-white transition hover:shadow-lg"
        >
          Explorer
        </Link>
      </div>
    </header>
  );
}
